from __future__ import annotations
import json, time
from dataclasses import dataclass, field, asdict
from pathlib import Path
from typing import Optional

@dataclass
class ExceptionRegisterEntry:
    exception_id:   str
    exception_type: str    # "label_dispute" | "app_override" | "urgent_ingestion" | "arbitration"
    doc_id:         str
    status:         str    # "open" | "resolved" | "withdrawn"
    raised_by:      str
    raised_utc:     float
    resolved_utc:   Optional[float] = None
    resolution_summary: str = ""

class ExceptionRegister:
    def __init__(self, path: Path):
        self.path = path

    def append(self, entry: ExceptionRegisterEntry) -> None:
        with self.path.open("a") as f:
            f.write(json.dumps(asdict(entry), default=str) + "\n")

    def open_exceptions(self) -> list[ExceptionRegisterEntry]:
        items = []
        for line in self.path.read_text().splitlines():
            if not line.strip():
                continue
            data = json.loads(line)
            if data.get("status") == "open":
                items.append(ExceptionRegisterEntry(**data))
        return items

    def stale_exceptions(self, stale_days: float = 14.0) -> list[ExceptionRegisterEntry]:
        now = time.time()
        return [e for e in self.open_exceptions()
                if (now - e.raised_utc) / 86400 > stale_days]

    def exception_rate_by_type(self, period_days: int = 90) -> dict[str, int]:
        cutoff = time.time() - period_days * 86400
        counts: dict[str, int] = {}
        for line in self.path.read_text().splitlines():
            if not line.strip():
                continue
            data = json.loads(line)
            if data.get("raised_utc", 0) > cutoff:
                t = data.get("exception_type", "unknown")
                counts[t] = counts.get(t, 0) + 1
        return counts
